// Solution
function validatePortMapping(portMapping) {
    if (!portMapping) {
        return 'Invalid';
    }
    var parts = portMapping.split(':');
    if (parts.length !== 2) {
        return 'Invalid';
    }
    var exposedPort = parseInt(parts[0]);
    var publishedPort = parseInt(parts[1]);
    if (isNaN(exposedPort) || isNaN(publishedPort)) {
        return 'Invalid';
    }
    if (publishedPort <= exposedPort) {
        return 'Invalid';
    }
    if (exposedPort > 65535 || publishedPort > 65535) {
        return 'Invalid';
    }
    return 'Valid';
}

