class Solution:
    def validatePortMapping(self, portMapping: str) -> str:
        if not portMapping:
            return 'Invalid'
        parts = portMapping.split(':')
        if len(parts) != 2:
            return 'Invalid'
        exposedPort = int(parts[0])
        publishedPort = int(parts[1])
        if not exposedPort or not publishedPort:
            return 'Invalid'
        if exposedPort > 65535 or publishedPort > 65535:
            return 'Invalid'
        if publishedPort <= exposedPort:
            return 'Invalid'
        return 'Valid'
